class Solution {
public:
    int maxStability(int n, vector<vector<int>>& edges, int k) {
        vector<tuple<int,int,int,int>> es;
        for (auto& e : edges) {
            int u = e[0], v = e[1], s = e[2], must = e[3];
            es.emplace_back(s, u, v, must);
        }
        sort(es.begin(), es.end());
        int m = es.size();
        int lo = 0, hi = 2e5 + 5, ans = -1;
        while (lo <= hi) {
            int mid = lo + (hi - lo) / 2;
            DSU dsu(n);
            int used = 0;
            for (auto [s, u, v, must] : es) {
                if (must) {
                    if (dsu.find(u) != dsu.find(v)) {
                        dsu.unite(u, v);
                    }
                }
            }
            for (auto [s, u, v, must] : es) {
                if (!must) {
                    int val = (s >= mid) ? s : (s * 2);
                    if (val >= mid && dsu.find(u) != dsu.find(v)) {
                        dsu.unite(u, v);
                        if (val == s * 2) used++;
                    }
                }
            }
            if (dsu.components == 1 && used <= k) {
                ans = mid;
                lo = mid + 1;
            } else {
                hi = mid - 1;
            }
        }
        return ans;
    }
private:
    struct DSU {
        vector<int> parent;
        int components;
        DSU(int n) : parent(n), components(n) {
            iota(parent.begin(), parent.end(), 0);
        }
        int find(int u) {
            if (parent[u] != u) parent[u] = find(parent[u]);
            return parent[u];
        }
        bool unite(int u, int v) {
            int pu = find(u), pv = find(v);
            if (pu == pv) return false;
            parent[pv] = pu;
            components--;
            return true;
        }
    };
};
